INSERT INTO soal_tiga_besar (id, pertanyaan, jawaban_paling_tepat, penjelasan_jawaban, level) VALUES
(1, 'Jika kamu terpilih sebagai Remaja Teladan GMIM, apa langkah konkret pertama yang akan kamu lakukan untuk menghidupkan visi "Remaja Bagi Kristus" di jemaatmu?', 'Langkah pertama saya adalah membentuk komunitas doa pagi online bagi remaja jemaat. Setiap hari Senin-Jumat pukul 05.30-06.00 WITA, kami berdoa bersama via Zoom/Google Meet. Saya akan mengajak minimal 5 orang remaja terlebih dahulu, lalu mereka mengajak teman-temannya. Doa pagi akan fokus pada: 1) Kekuatan rohani remaja; 2) Kelancaran studi; 3) Kebangunan rohani di sekolah; 4) Jemaat dan pelayanan. Saya akan membuat grup WhatsApp khusus untuk koordinasi dan membagikan ayat Alkitab setiap hari. Target dalam 3 bulan: 30 remaja aktif berdoa pagi.', 'Poin penilaian: Inisiatif (langkah konkret, bukan wacana), keberlanjutan (bisa dilanjutkan setelah masa jabatan), keterukuran (target jelas), relevansi dengan visi "Remaja Bagi Kristus" (doa adalah fondasi). Juri mencari peserta yang action-oriented, bukan hanya teori.', 'final'),
(2, 'Dalam situasi tekanan teman sebaya (peer pressure) yang negatif, bagaimana kamu menunjukkan sikap sebagai remaja teladan berdasarkan teladan Yesus?', 'Saya akan meneladani Yesus yang menjawab godaan Iblis dengan Firman Tuhan (Matius 4:1-11). Ketika diajak merokok, saya akan berkata: "Maaf, tubuhku adalah bait Roh Kudus (1 Korintus 6:19), aku tidak mau merusaknya." Saya tidak akan menghakimi teman yang merokok, tetapi dengan lembut menjelaskan dampaknya. Saya juga akan mengajak mereka melakukan aktivitas positif: olahraga, bermain musik, atau belajar Alkitab. Yang terpenting, saya tetap berteman dengan mereka, tidak menjauhi, karena Yesus juga bergaul dengan pemungut cukai dan orang berdosa untuk menjangkau mereka (Matius 9:10-13).', 'Poin penilaian: Keberanian moral (berkata tidak), penggunaan Firman Tuhan sebagai senjata, keteladanan Yesus (tidak menghakimi tetapi mengasihi), solusi alternatif (mengajak ke aktivitas positif). Juri menilai keseimbangan antara ketegasan dan kasih.', 'final'),
(3, 'Buatlah sebuah rencana aksi kecil yang bisa kamu lakukan dalam 1 minggu ke depan untuk menjadi berkat bagi lingkungan sekolah atau masyarakat sekitarmu.', 'Dalam 1 minggu ke depan, saya akan melaksanakan "Gerakan 1 Sampah 1 Senyum" di sekolah. Setiap hari saat istirahat, saya akan memungut minimal 5 sampah plastik yang berserakan di halaman sekolah. Sampah yang terkumpul akan saya pilah: yang bisa didaur ulang saya serahkan ke bank sampah sekolah, yang residu saya buang ke tempatnya. Saya akan mengajak 3 teman dekat untuk melakukan hal yang sama. Di setiap sampah yang saya pungut, saya akan ucapkan doa singkat: "Tuhan, berkatilah pemilik sampah ini." Tujuannya: membersihkan lingkungan sambil mendoakan teman-teman yang belum sadar kebersihan. Hasil yang saya harapkan: lingkungan lebih bersih, dan teman-teman terinspirasi untuk ikut.', 'Poin penilaian: Konkret (dapat dilakukan segera), terukur (5 sampah/hari), berdampak ganda (lingkungan + doa), dapat ditiru orang lain, tidak membutuhkan biaya besar. Juri menyukai aksi nyata yang sederhana tetapi berdampak.', 'final'),
(4, 'Menurutmu, apa tantangan terbesar yang dihadapi remaja Kristen di era media sosial saat ini, dan bagaimana solusinya?', 'Tantangan terbesar adalah hoaks dan konten negatif yang merusak iman dan karakter. Remaja mudah terpapar konten pornografi, ujaran kebencian, perundungan digital, dan ajaran sesat. Solusinya: 1) Membangun literasi digital melalui pelatihan di gereja tentang cara memverifikasi informasi; 2) Membuat konten rohani yang menarik (podcast, video TikTok, Instagram Reels) untuk membanjiri algoritma dengan konten positif; 3) Membentuk komunitas digital sehat di WA/Telegram untuk saling mengingatkan; 4) Pendampingan orang tua – remaja teladan dapat menjadi jembatan antara orang tua dan remaja dengan mengadakan seminar parenting. 5) Yang terpenting: membangun identitas diri dalam Kristus sehingga tidak mudah terpengaruh oleh tren dunia.', 'Poin penilaian: Analisis masalah yang tajam (tidak asal jawab), solusi sistemik (bukan hanya individual), peran remaja teladan sebagai agen perubahan, keterkaitan dengan iman Kristen. Juri mencari peserta yang kritis dan solutif.', 'final'),
(5, 'Bagaimana cara Anda menyikapi perbedaan pendapat yang tajam dengan teman sepelayanan dalam organisasi remaja?', 'Saya akan mengikuti prinsip Matius 18:15-17 dan prinsip musyawarah. Pertama, saya akan berbicara empat mata dengan teman tersebut di tempat netral, dengan hati yang rendah hati. Saya akan mendengarkan dulu sudut pandangnya tanpa memotong (Yakobus 1:19). Kedua, saya akan fokus pada masalah, bukan pribadi – saya tidak akan menyerang karakter orangnya. Ketiga, jika belum selesai, saya akan melibatkan pembina remaja sebagai mediator. Keempat, saya siap mengalah untuk hal-hal yang tidak prinsipil, demi persatuan. Kelima, jika saya yang salah, saya akan minta maaf dengan tulus di depan umum. Contoh nyata: pernah ada perbedaan pendapat tentang tema kegiatan Paskah; setelah diskusi, kami memutuskan untuk menggabungkan kedua ide menjadi satu tema yang lebih baik.', 'Poin penilaian: Prosedur penyelesaian konflik yang alkitabiah, kerendahan hati, kemampuan kompromi, contoh konkret (pengalaman pribadi lebih baik). Juri menilai kematangan emosi dan kerohanian.', 'final'),
(6, 'Jika Anda menjadi Ketua Komisi Pelayanan Remaja Jemaat, program apa yang akan Anda prioritas kan dan mengapa?', 'Saya akan memprioritaskan program penguatan fondasi iman, yaitu Pendalaman Alkitab (PA) yang sistematis dan menarik. Mengapa? Karena banyak remaja yang goyah imannya karena tidak memiliki dasar Firman yang kuat. Programnya: 1) PA Kreatif setiap Sabtu sore dengan metode yang variatif (diskusi, games, drama, multimedia); 2) Tantangan Baca Alkitab 30 hari dengan reward yang memotivasi; 3) Sahabat Doa – pairing antar remaja untuk saling mendoakan dan mengingatkan; 4) Apresiasi bagi remaja yang konsisten membaca Alkitab. Target: dalam 6 bulan, 80% remaja aktif membaca Alkitab minimal 1 pasal per hari. Karena jika imannya kuat, pelayanan lain akan mengikuti.', 'Poin penilaian: Alasan yang kuat (mengapa program itu diprioritaskan), program terstruktur dan terukur, fokus pada fondasi (bukan hanya aktivitas seremonial), visi jangka panjang. Juri ingin melihat peserta yang memahami prioritas pelayanan.', 'final'),
(7, 'Apa arti "Menjadi Teladan" bagi Anda secara pribadi, dan bagaimana Anda mewujudkannya dalam kehidupan sehari-hari?', 'Bagi saya, "menjadi teladan" berarti hidup yang konsisten antara perkataan dan perbuatan, baik di depan umum maupun ketika sendirian. Saya mewujudkannya dengan: 1) Di sekolah – saya tidak menyontek, mengerjakan tugas tepat waktu, dan membantu teman yang kesulitan, tanpa mencari pujian; 2) Di rumah – saya membantu orang tua tanpa diminta, berbicara dengan sopan, dan mengalah pada adik; 3) Di gereja – saya datang lebih awal, duduk di depan, aktif dalam pelayanan, dan memberi perhatian pada remaja yang terpinggirkan; 4) Di media sosial – saya hanya memposting konten yang membangun, tidak ikut-ikutan hate speech, dan berani menegur teman yang memposting hal negatif. Saya sadar bahwa sebagai remaja teladan, hidup saya bukan milik saya lagi, tetapi menjadi surat terbuka yang dibaca semua orang (2 Korintus 3:2).', 'Poin penilaian: Definisi yang alkitabiah, aplikasi konkret di berbagai konteks (sekolah, rumah, gereja, medsos), kesadaran akan pengawasan publik, kerendahan hati (bukan mencari pujian). Juri mencari autentisitas dan konsistensi.', 'final'),
(8, 'Bagaimana Anda menyeimbangkan antara prestasi akademik, pelayanan gereja, dan kehidupan sosial sebagai remaja?', 'Kuncinya adalah manajemen waktu yang disiplin dan skala prioritas. Saya membuat jadwal mingguan: 1) Prioritas utama: Tuhan – setiap pagi 30 menit doa dan baca Alkitab sebelum berangkat sekolah; 2) Prioritas kedua: belajar – saya belajar dari jam 7-9 malam, tanpa HP; 3) Prioritas ketiga: pelayanan – saya hanya mengambil 2 pelayanan aktif (paduan suara dan pengurus remaja) agar tidak overcommitment; 4) Prioritas keempat: sosial – saya menggunakan Sabtu sore untuk hangout dengan teman-teman. Saya juga belajar mengatakan "tidak" untuk kegiatan yang tidak penting, dan tidak menunda-nunda pekerjaan. Saya mempraktekkan Efesus 5:16 – "Pergunakanlah waktu yang baik, karena hari-hari ini adalah jahat." Hasilnya: nilai saya stabil, pelayanan berjalan, dan saya tetap memiliki teman-teman.', 'Poin penilaian: Praktis (ada sistem yang jelas), realistis (tidak idealis berlebihan), ada prinsip Alkitab, ada contoh konkret. Juri ingin melihat peserta yang teratur dan bertanggung jawab, bukan yang terbakar di ujung waktu.', 'final'),
(9, 'Apa pendapat Anda tentang fenomena "remaja malas ke gereja" saat ini, dan bagaimana Anda mengatasinya?', 'Fenomena ini disebabkan oleh beberapa faktor: 1) Ibadah yang membosankan (monoton, tidak relevan); 2) Pergaulan dunia yang lebih menarik; 3) Krisis identitas – remaja tidak melihat gereja sebagai "rumah" mereka; 4) Kepalsuan – remaja merasa gereja hanya untuk orang yang "sok suci". Solusi yang saya tawarkan: 1) Ibadah kreatif – menggunakan multimedia, musik kontemporer yang bermutu, khotbah yang singkat dan aplikatif; 2) Mentoring – setiap remaja baru memiliki kakak rohani yang mendampingi; 3) Pelayanan yang memberdayakan – beri remaja tanggung jawab nyata, bukan hanya jadi penonton; 4) Buka diri terhadap kritik – adakan kotak saran anonim; 5) Jemput bola – kunjungi remaja yang jarang datang, dengarkan keluh kesah mereka tanpa menghakimi. Saya sudah mempraktekkan ini: saya mengajak 2 teman yang jarang ke gereja dengan menjemput mereka dan mentraktir bakso setelah ibadah. Sekarang mereka sudah rutin hadir.', 'Poin penilaian: Analisis penyebab yang mendalam (tidak menyalahkan remaja begitu saja), solusi yang holistik dan praktis, contoh keberhasilan pribadi, semangat menjangkau bukan menghakimi. Juri menilai empati dan kreativitas.', 'final'),
(10, 'Jika Anda diminta menjadi pembicara dalam ibadah remaja dengan tema "Bangkit dan Bersinar", apa poin utama yang akan Anda sampaikan?', 'Saya akan menyampaikan 3 poin utama dari Yesaya 60:1-3: 1) "Bangkitlah" dari keterpurukan – banyak remaja merasa tidak berharga, gagal, atau tertekan. Saya akan menyampaikan bahwa dalam Kristus kita memiliki identitas baru, kita adalah anak-anak Raja. Kita tidak perlu tinggal dalam kegelapan dosa dan keputusasaan. 2) "Menjadi terang" di tempat gelap – sekolah, keluarga, lingkungan kita adalah tempat gelap yang butuh terang. Saya akan memberikan contoh konkret: menjadi terang dengan tidak ikut menyontek, menjadi terang dengan berani mengatakan kebenaran, menjadi terang dengan menolong yang lemah. 3) "Kemuliaan Tuhan menyinari" – kita tidak bersinar dengan kekuatan sendiri, tetapi karena kemuliaan Tuhan yang memantul dalam hidup kita. Saya akan menutup dengan ajakan: "Mari kita berkomitmen untuk menjadi remaja yang bangkit dari kemalasan, ketakutan, dan dosa, lalu bersinar di mana pun kita berada!"', 'Poin penilaian: Struktur khotbah yang jelas (3 poin), aplikatif (ada contoh konkret), alkitabiah, antusiasme dan kemampuan komunikasi yang baik. Juri menilai kemampuan public speaking dan penguasaan materi.', 'final'),
(11, 'Bagaimana sikap Anda terhadap remaja yang berbeda denominasi atau berbeda agama? Apakah Anda mau berteman dengan mereka?', 'Saya sangat mau berteman dengan mereka. Sebagai remaja Kristen, saya dipanggil untuk mengasihi sesama tanpa syarat, seperti yang Yesus ajarkan dalam perumpamaan Orang Samaria yang Baik Hati (Lukas 10:25-37). Saya memiliki teman dekat yang beragama Islam dan Katolik. Kami saling menghormati: saya tidak memaksakan mereka ikut kegiatan gereja, dan mereka tidak memaksa saya ikut ibadah mereka. Kami berteman dalam hal-hal yang bisa kami lakukan bersama: belajar, olahraga, makan bersama, dan saling membantu dalam kesulitan. Namun, saya juga tetap setia pada iman saya – saya tidak akan ikut ibadah mereka, dan saya akan dengan hormat menjelaskan keyakinan saya jika ditanya. Saya percaya bahwa persahabatan yang tulus adalah jembatan untuk bersaksi, bukan dengan kata-kata tetapi dengan kasih yang nyata.', 'Poin penilaian: Toleransi tanpa kompromi iman, teladan Yesus dalam mengasihi semua orang, batasan yang jelas (tidak ikut ibadah mereka), kesaksian melalui perbuatan. Juri menilai keseimbangan antara kasih dan kebenaran.', 'final'),
(12, 'Apa kontribusi nyata yang bisa remaja berikan untuk pembangunan bangsa di tengah krisis moral saat ini?', 'Remaja bisa menjadi agen perubahan moral di lingkungan terkecil mereka. Kontribusi nyata yang bisa saya lakukan: 1) Di sekolah: menjadi duta anti-bullying, melaporkan perundungan yang saya lihat, dan membela korban; 2) Di media sosial: membuat konten positif yang mengedukasi tentang bahaya narkoba, seks bebas, dan hoaks; tidak ikut menyebarkan ujaran kebencian; 3) Di masyarakat: ikut gotong royong, mengajar mengaji atau baca Alkitab untuk adik-adik yang putus sekolah; 4) Di gereja: menjadi teladan dalam kejujuran dan integritas, sehingga orang lain terinspirasi. Saya percaya bahwa perubahan besar dimulai dari hal kecil. Jika setiap remaja Kristen berkomitmen untuk menjadi garam dan terang di tempatnya masing-masing, bangsa ini akan berubah. Saya tidak perlu menunggu dewasa untuk berkontribusi; sekarang juga saya bisa memulai.', 'Poin penilaian: Kesadaran akan peran remaja dalam pembangunan bangsa, contoh konkret yang bisa dilakukan remaja, semangat memulai dari diri sendiri, relevan dengan kondisi bangsa saat ini. Juri menilai nasionalisme dan kepedulian sosial.', 'final'),
(13, 'Bagaimana Anda mempersiapkan diri untuk menghadapi godaan di era digital, terutama pornografi dan judi online?', 'Saya mempersiapkan diri dengan 4 strategi: 1) Filter digital – saya memasang aplikasi seperti Covenant Eyes atau parental control di HP saya, dan meminta orang tua atau pembina remaja menjadi "accountability partner" yang bisa melihat aktivitas online saya; 2) Mengisi waktu luang – saya memiliki jadwal kegiatan yang padat: belajar, olahraga, latihan musik, dan pelayanan, sehingga tidak ada waktu luang yang panjang untuk hal-hal negatif; 3) Pergaulan sehat – saya memilih teman yang memiliki komitmen sama untuk hidup kudus, dan saling mengingatkan; 4) Firman Tuhan – saya menghafalkan ayat-ayat kunci seperti Ayub 31:1, "Aku telah membuat perjanjian dengan mataku; mengapa aku akan melirik anak dara?" dan Mazmur 119:9, "Dengan apakah seorang muda mempertahankan kelakuannya bersih? Dengan menjaganya sesuai dengan firman-Mu." Jika godaan datang, saya langsung berdoa dan membaca Alkitab.', 'Poin penilaian: Strategi yang proaktif (bukan reaktif), penggunaan teknologi untuk kebaikan, akuntabilitas (accountability), hafalan ayat Alkitab, kesadaran akan bahaya. Juri menilai kewaspadaan dan persiapan yang matang.', 'final'),
(14, 'Apa yang akan Anda lakukan jika melihat teman sekelas mengalami depresi dan memiliki kecenderungan bunuh diri?', 'Langkah pertama: saya akan mendekati dia dengan empati, tidak dengan menghakimi. Saya akan ajak bicara berdua di tempat yang tenang, mendengarkan tanpa memotong, dan meyakinkan dia bahwa saya peduli. Saya akan mengatakan: "Kamu tidak sendirian, aku di sini untukmu." Langkah kedua: saya akan mengajak dia bercerita kepada orang dewasa yang dipercaya, seperti guru BK, orang tua, atau pembina remaja. Saya akan mendampinginya saat bercerita, agar dia tidak merasa sendirian. Langkah ketiga: saya akan mendoakan dia setiap hari dan terus memantau kondisinya. Langkah keempat: saya akan mengajak dia melakukan aktivitas positif bersama, seperti olahraga atau bermain musik, untuk mengalihkan pikiran negatif. Saya tidak akan menyimpan sendiri rahasia ini karena menyangkut nyawa. Seperti dalam Galatia 6:2, "Bertolong-tolonganlah menanggung bebanmu."', 'Poin penilaian: Empati dan kepedulian, prosedur yang benar (melibatkan orang dewasa), tidak menyimpan rahasia yang membahayakan, dukungan berkelanjutan, landasan Alkitab. Juri menilai kematangan dan tanggung jawab sosial.', 'final'),
(15, 'Menurut Anda, apa kriteria utama seorang remaja dapat disebut "teladan" di era modern ini?', 'Menurut saya, kriteria utama remaja teladan di era modern adalah integritas digital – konsisten antara kehidupan online dan offline. Di era di mana orang bisa "pura-pura" menjadi berbeda di media sosial, remaja teladan adalah yang asli (autentik). Kriteria lainnya: 1) Memiliki identitas yang kuat dalam Kristus, tidak goyah oleh tren atau cancel culture; 2) Mampu berpikir kritis – tidak mudah termakan hoaks, bisa membedakan mana yang benar dan salah; 3) Berkarakter – jujur, bertanggung jawab, rendah hati, disiplin, dan berani; 4) Berempati – peka terhadap penderitaan orang lain, baik online maupun offline; 5) Tidak hanya baik di gereja, tetapi juga di sekolah, rumah, dan masyarakat. Remaja teladan bukan yang sempurna tanpa dosa, tetapi yang bertobat dan terus bertumbuh setiap hari.', 'Poin penilaian: Definisi yang relevan dengan zaman (integritas digital), tidak hanya kriteria tradisional, keseimbangan antara iman dan kecerdasan, kerendahan hati (mengakui tidak sempurna). Juri menilai pemahaman kontekstual dan kematangan berpikir.', 'final'),
(16, 'Bagaimana cara Anda mengajak teman yang belum percaya Yesus untuk mengenal Tuhan tanpa terkesan memaksa?', 'Saya menggunakan pendekatan "attraction, not promotion" – menarik, bukan memaksa. Caranya: 1) Menjadi teladan – saya menunjukkan perubahan hidup yang positif: lebih sabar, jujur, dan peduli. Ketika teman bertanya, "Kok kamu beda?" saya menjawab, "Karena Yesus mengubah hidupku." 2) Menjadi sahabat tulus – saya tidak bersaksi dengan khotbah, tetapi dengan tindakan nyata: membantu PR, menemani saat sedih, dan mendoakan mereka diam-diam. 3) Mengajak dengan cara yang tidak mengintimidasi – "Eh, kebetulan di gerejaku ada acara bakti sosial, yuk ikut. Kita bisa main juga kok." atau "Di gerejaku ada konser musik rohani yang keren, mau nonton?" 4) Menghormati kebebasan mereka – jika mereka menolak, saya tidak memaksa, tetapi tetap berteman seperti biasa. Saya percaya bahwa kasih yang tulus adalah bahasa universal yang paling efektif untuk bersaksi.', 'Poin penilaian: Pendekatan yang tidak memaksa, teladan hidup lebih kuat dari kata-kata, strategi "door in the face" (mengajak kegiatan ringan dulu), menghormati kebebasan orang lain, kesabaran dalam bersaksi. Juri menilai kearifan dalam penginjilan.', 'final'),
(17, 'Apa pendapat Anda tentang pernikahan dini yang marak terjadi di kalangan remaja saat ini?', 'Saya menilai pernikahan dini (di bawah usia 19 tahun) sebagai fenomena yang merugikan dan tidak sesuai dengan prinsip Alkitab maupun undang-undang. Dampak negatifnya: 1) Kesiapan mental – remja belum stabil secara emosi untuk mengelola konflik rumah tangga; 2) Kesiapan finansial – remaja belum bekerja, sehingga membebani orang tua; 3) Pendidikan terputus – banyak yang putus sekolah, masa depan suram; 4) Kesehatan reproduksi – kehamilan di usia muda berisiko tinggi; 5) Tingkat perceraian tinggi. Sebagai remaja teladan, saya akan: 1) Memberikan edukasi kepada teman-teman tentang bahaya pernikahan dini; 2) Menjadi contoh dengan fokus pada studi dan pelayanan, bukan pacaran serius; 3) Mendukung program gereja tentang pendidikan seksualitas yang sehat; 4) Jika ada teman yang terdesak, saya akan mengarahkan mereka ke pembina remaja atau psikolog untuk konseling. Alkitab mengajarkan bahwa pernikahan adalah persekutuan seumur hidup yang harus dipersiapkan dengan matang, bukan pelarian dari masalah.', 'Poin penilaian: Analisis dampak yang komprehensif (mental, finansial, pendidikan, kesehatan), sikap proaktif (edukasi, bukan hanya menghakimi), solusi nyata, landasan Alkitab. Juri menilai pemahaman tentang kesehatan reproduksi dan kesiapan berkeluarga.', 'final'),
(18, 'Jika Anda gagal menjadi juara dalam Pemilihan Remaja Teladan ini, bagaimana sikap Anda?', 'Saya akan tetap bersyukur dan bangga karena sudah sampai di babak 3 Besar. Kegagalan bukan akhir dari segalanya. Saya akan: 1) Mengevaluasi diri – apa kekurangan saya? Saya akan bertanya kepada juri atau pembina untuk masukan, agar saya bisa lebih baik ke depannya; 2) Tetap melayani – gelar bukan tujuan saya; tujuan saya adalah menjadi remaja yang berguna bagi Tuhan dan sesama, dengan atau tanpa gelar; 3) Mendukung pemenang – saya akan memberi selamat dengan tulus, karena saya yakin juri sudah memilih yang terbaik; 4) Terus bertumbuh – saya akan mengikuti pembinaan selanjutnya, belajar lebih giat, dan mencoba lagi di tahun berikutnya jika masih memenuhi syarat usia. Saya ingat kata Amsal 24:16, "Sebab tujuh kali orang benar jatuh, namun ia bangkit kembali." Saya tidak akan menyerah.', 'Poin penilaian: Sportivitas, kemampuan menerima kegagalan, sikap positif (belajar dari kegagalan), tidak menganggap gelar sebagai segalanya, semangat pantang menyerah. Juri menilai kematangan emosi dan kerendahan hati.', 'final'),
(19, 'Bagaimana cara Anda menyikapi ajaran sesat atau aliran Kristen yang menyimpang yang masuk ke lingkungan remaja?', 'Saya akan bersikap dengan bijaksana dan berdasarkan Firman Tuhan. Langkah-langkahnya: 1) Mempelajari ajaran yang benar – saya harus tahu dulu apa yang Alkitab ajarkan, baru bisa mengenali ajaran sesat. Saya aktif dalam PA dan membaca buku-buku teologi yang baik; 2) Mendekati dengan kasih, bukan musuhan – jika ada teman yang terpengaruh, saya tidak akan memusuhi atau menghakimi. Saya akan mengajak ngobrol empat mata, mendengarkan keyakinannya, dan dengan lembut menunjukkan kebenaran Alkitab (1 Petrus 3:15-16); 3) Melaporkan kepada pembina – jika ajaran itu berbahaya dan sudah menyebar luas, saya akan melaporkan kepada pembina remaja atau pendeta untuk ditindaklanjuti; 4) Mendoakan – saya akan berdoa agar mereka diberi hikmat untuk melihat kebenaran. Saya tidak akan berdebat keras di media sosial karena itu tidak efektif dan hanya memperkeruh suasana.', 'Poin penilaian: Pengetahuan akan kebenaran (fondasi), pendekatan yang lembut dan penuh kasih (bukan kekerasan), pelibatan otoritas gereja, doa, menghindari perdebatan publik. Juri menilai kearifan dalam menghadapi perbedaan teologis.', 'final'),
(20, 'Apa yang akan Anda lakukan untuk melestarikan budaya Minahasa di tengah gempuran budaya asing?', 'Saya akan melakukan 3 hal konkret: 1) Belajar dan menguasai budaya sendiri – saya aktif belajar menari Maengket, memainkan kolintang, dan mempelajari bahasa Tombulu. Saya tidak malu menampilkan budaya Minahasa di acara sekolah atau media sosial. Saya akan membuat konten TikTok tentang budaya Minahasa dengan kemasan modern yang menarik remaja; 2) Mengajak teman-teman – saya akan membentuk sanggar seni budaya remaja di gereja. Setiap Sabtu, kami berlatih kolintang, Maengket, dan membuat kerajinan tradisional. Target: bisa tampil di acara gereja dan festival budaya; 3) Memodifikasi, tidak meninggalkan – budaya harus relevan dengan zaman. Saya akan mengkolaborasikan kolintang dengan musik modern, atau Maengket dengan koreografi kekinian, tanpa menghilangkan esensinya. Saya juga akan menggunakan media sosial untuk mempromosikan budaya Minahasa ke khalayak yang lebih luas. Seperti kata pepatah: "Tak kenal maka tak sayang" – jika remaja mengenal budayanya, mereka akan mencintainya.', 'Poin penilaian: Aksi konkret (belajar, mengajak, mempromosikan), penggunaan media sosial untuk pelestarian, inovasi tanpa meninggalkan esensi, semangat menjadi duta budaya. Juri menilai kecintaan pada budaya lokal dan kreativitas.', 'final'),
(21, 'Bagaimana Anda akan memimpin sebuah tim yang terdiri dari orang-orang dengan karakter yang sangat berbeda?', 'Saya akan memimpin dengan prinsip "melayani, bukan memerintah" (Yohanes 13:1-17). Langkah saya: 1) Mengenal anggota tim secara personal – saya akan mengadakan sesi perkenalan yang mendalam, mengetahui kekuatan, kelemahan, minat, dan gaya kerja masing-masing; 2) Menempatkan orang sesuai talenta – seperti dalam 1 Korintus 12, setiap anggota memiliki karunia berbeda. Yang suka detail saya tugaskan sebagai bendahara, yang kreatif sebagai seksi acara, yang tegas sebagai koordinator lapangan; 3) Membangun komunikasi terbuka – saya akan mengadakan sharing session rutin di mana semua orang bisa mengeluarkan pendapat tanpa takut dihakimi; 4) Menjadi penengah konflik – jika ada gesekan, saya akan memediasi dengan adil, tidak memihak; 5) Merayakan keberagaman – saya akan mengadakan kegiatan tim building yang menghargai perbedaan, seperti potluck (makanan khas daerah masing-masing) atau games yang membutuhkan kerjasama. Saya percaya bahwa tim yang beragam justru lebih kuat karena saling melengkapi.', 'Poin penilaian: Pemahaman tentang gaya kepemimpinan (servant leadership), strategi pengelolaan tim yang sistematis, pemanfaatan keberagaman, penyelesaian konflik, perayaan perbedaan. Juri menilai kemampuan manajerial dan kepemimpinan kolektif.', 'final'),
(22, 'Apa arti "Kasih" menurut 1 Korintus 13 bagi kehidupan remaja masa kini?', '1 Korintus 13 memberikan standar kasih yang sangat tinggi, tetapi bukan tidak mungkin untuk diupayakan. Bagi remaja masa kini, artinya: 1) "Kasih itu sabar" – tidak marah ketika teman menghina di medsos, tidak terprovokasi; 2) "Kasih itu murah hati" – mau berbagi makanan, catatan pelajaran, atau waktu untuk mendengarkan teman yang sedang sedih; 3) "Kasih itu tidak cemburu" – tidak iri ketika teman mendapat nilai lebih baik atau dipuji guru; 4) "Kasih itu tidak memegahkan diri" – tidak pamer pencapaian di media sosial untuk mencari pujian; 5) "Kasih itu tidak melakukan yang tidak sopan" – tidak berkata kotor, tidak mengirim pesan mesum, tidak bergosip; 6) "Kasih itu tidak mencari keuntungan sendiri" – dalam kerja kelompok, tidak hanya mengerjakan bagian yang mudah; 7) "Kasih itu menutupi segala sesuatu" – tidak menyebarkan aib teman. Saya berusaha mempraktekkan kasih ini setiap hari, meskipun sering gagal. Tapi saya terus belajar.', 'Poin penilaian: Aplikasi ayat Alkitab yang terkenal ke dalam konteks remaja (medsos, sekolah, pergaulan), contoh-contoh yang relevan, kerendahan hati mengakui kegagalan, komitmen untuk terus belajar. Juri menilai pemahaman yang mendalam tentang kasih dalam kehidupan nyata.', 'final'),
(23, 'Jika Anda diberi kesempatan untuk mengubah satu hal di gereja Anda, apa yang akan Anda ubah dan mengapa?', 'Saya akan mengubah pola ibadah remaja yang lebih partisipatif dan interaktif. Selama ini, ibadah remaja cenderung satu arah: pemimpin ibadah berbicara, remaja mendengarkan. Saya ingin ibadah remaja menjadi ruang di mana remaja bisa bertanya, berdiskusi, dan berkontribusi. Bentuknya: 1) Sesi tanya jawab interaktif setelah khotbah, remaja bisa bertanya atau memberikan tanggapan; 2) Remaja menjadi pengkhotbah secara bergilir (setelah dilatih), sehingga mereka belajar dan memiliki rasa memiliki; 3) Penggunaan media yang relevan – video pendek, polling real-time via HP, games edukatif; 4) Waktu sharing yang cukup untuk remaja menceritakan pergumulan mereka. Mengapa? Karena remaja zaman now tidak mau hanya menjadi penonton; mereka ingin terlibat dan didengar. Saya percaya bahwa ibadah yang partisipatif akan membuat remaja lebih antusias dan bertumbuh imannya.', 'Poin penilaian: Ide yang spesifik dan aplikatif, alasan yang kuat (mengapa perubahan itu perlu), solusi yang realistis, pemahaman tentang kebutuhan remaja masa kini, semangat memberdayakan remaja. Juri menilai kreativitas dalam pelayanan dan kepedulian terhadap efektivitas ibadah.', 'final'),
(24, 'Bagaimana cara Anda membangun rasa percaya diri sebagai remaja yang hidup di era standar kecantikan dan kesempurnaan yang tidak realistis dari media sosial?', 'Saya membangun rasa percaya diri dengan mengubah sumber validasi saya. Bukan dari jumlah like atau komentar, tetapi dari Firman Tuhan. Mazmur 139:14 berkata, "Aku bersyukur kepada-Mu karena kejadianku dahsyat dan ajaib." Artinya, saya diciptakan unik oleh Tuhan, tidak perlu menjadi seperti orang lain. Langkah praktis saya: 1) Membatasi waktu medsos – saya hanya menggunakan medsos maksimal 2 jam sehari, tidak membandingkan hidup saya dengan highlight reel orang lain; 2) Fokus pada kelebihan saya – saya punya bakat bermusik, jadi saya mengembangkannya dan menggunakannya untuk melayani, bukan untuk pamer; 3) Mengikuti akun yang positif – saya unfollow akun yang membuat saya insecure, follow akun yang menginspirasi dan membangun; 4) Memiliki komunitas yang mendukung – teman-teman di gereja saling mengingatkan bahwa kita berharga bukan karena penampilan; 5) Bersyukur setiap hari – saya menulis 3 hal yang saya syukuri dari diri saya setiap malam. Saya belajar bahwa kecantikan sejati berasal dari hati yang takut akan Tuhan.', 'Poin penilaian: Pemahaman tentang dampak negatif medsos, strategi yang sehat (membatasi, memfilter, fokus pada kelebihan), landasan Alkitab, komunitas pendukung, praktik bersyukur. Juri menilai kesehatan mental dan identitas diri yang kuat.', 'final'),
(25, 'Apa yang akan Anda lakukan jika menjadi pengurus komisi remaja tetapi banyak anggota yang tidak aktif dan tidak mau terlibat?', 'Saya akan melakukan pendekatan personal, bukan general. Langkah-langkahnya: 1) Mendata anggota yang tidak aktif – siapa saja mereka, berapa lama tidak hadir; 2) Mengunjungi satu per satu – saya akan menjenguk mereka ke rumah atau bertemu di sekolah, dengan sikap yang ramah, bukan menghakimi. Saya akan bertanya dengan tulus: "Ada apa? Apa yang membuatmu tidak datang lagi? Apakah ada yang bisa saya bantu?" 3) Mendengarkan keluhan mereka – mungkin mereka bosan dengan kegiatan, merasa tidak dihargai, atau ada masalah pribadi; 4) Melibatkan mereka dalam pengambilan keputusan – saya akan mengadakan musyawarah untuk menyusun program kerja, dan mengundang semua anggota termasuk yang tidak aktif; 5) Memberi tanggung jawab kecil – ketika mereka datang, saya akan memberikan tugas yang ringan tapi penting, seperti membawa snack atau menjadi notulis, agar mereka merasa dibutuhkan; 6) Menciptakan kegiatan yang fun – tidak selalu ibadah formal, tetapi juga outbond, nonton bareng, atau bakti sosial yang menarik. Saya percaya bahwa setiap remaja sebenarnya rindu terlibat, hanya butuh perhatian dan pendekatan yang tepat.', 'Poin penilaian: Analisis masalah, pendekatan personal (bukan generalisasi), empati, keterlibatan anggota dalam pengambilan keputusan, pemberian tanggung jawab, kegiatan yang bervariasi. Juri menilai kepemimpinan yang melayani dan kemampuan membangun tim.', 'final'),
(26, 'Menurut Anda, apa peran gereja dalam membentuk karakter remaja di era digital ini?', 'Peran gereja sangat krusial, yaitu menjadi "rumah kedua" dan "sekolah karakter" bagi remaja. Secara spesifik: 1) Pendamping digital – gereja harus memberikan literasi digital kepada remaja: bagaimana menggunakan medsos dengan bijak, melindungi diri dari konten negatif, dan menjadi terang di dunia digital. Gereja bisa mengadakan seminar tentang etika digital; 2) Menyediakan konten rohani yang menarik – gereja tidak boleh ketinggalan zaman. Buat podcast, YouTube channel, atau TikTok yang berisi pesan Alkitab dalam kemasan remaja; 3) Membangun komunitas yang aman – di tengah dunia maya yang dingin, gereja harus menjadi tempat di mana remaja bisa jujur tentang pergumulan mereka tanpa dihakimi, dan mendapatkan dukungan nyata; 4) Menjadi teladan melalui pembina – pembina remaja harus melek digital dan bisa menjadi contoh dalam menggunakan teknologi secara sehat; 5) Mengadakan kegiatan offline yang menarik – agar remaja tidak hanya terpaku pada dunia maya. Gereja harus menjadi oase di tengah hiruk pikuk digital.', 'Poin penilaian: Pemahaman tentang tantangan era digital, solusi yang konkret (literasi digital, konten, komunitas, teladan, kegiatan offline), peran gereja yang relevan, semangat adaptasi. Juri menilai visi tentang pelayanan remaja yang kontekstual.', 'final'),
(27, 'Bagaimana Anda menyikapi teman yang berbeda pilihan politik dengan Anda, terutama menjelang pemilu?', 'Saya akan menyikapinya dengan dewasa dan menghormati perbedaan. Prinsip saya: beda pilihan, tetap bersaudara. Langkah-langkah: 1) Tidak memaksakan pilihan – saya tidak akan berdebat atau memaksa teman untuk memilih calon yang sama dengan saya. Setiap orang punya hak pilih masing-masing; 2) Menghindari ujaran kebencian – saya tidak akan menghina calon yang tidak saya pilih, apalagi menghina teman yang memilih calon berbeda; 3) Mengedukasi dengan data, bukan hoaks – jika teman bertanya, saya akan menjelaskan alasan saya memilih calon tertentu berdasarkan program dan track record, bukan fitnah; 4) Tetap berteman setelah pemilu – apapun hasilnya, persahabatan saya tidak akan terganggu. Saya akan mengucapkan selamat kepada pemenang dan menghormati proses demokrasi; 5) Mendoakan para pemimpin – seperti yang diajarkan 1 Timotius 2:1-2, saya akan mendoakan semua pemimpin, baik yang saya pilih maupun tidak, agar mereka memimpin dengan bijaksana. Saya percaya bahwa perbedaan politik tidak boleh memecah belah persaudaraan.', 'Poin penilaian: Kedewasaan politik (tidak fanatik), penghormatan pada perbedaan, tidak menyebarkan hoaks, memprioritaskan persaudaraan, doa bagi pemimpin. Juri menilai sikap toleransi politik dan kedewasaan berpikir.', 'final'),
(28, 'Apa yang akan Anda lakukan jika melihat teman menggunakan narkoba?', 'Saya akan bertindak cepat karena menyangkut nyawa dan masa depan. Langkah saya: 1) Tidak panik, tetapi tidak diam – saya tidak akan menghakimi atau memusuhi dia, tetapi saya tidak bisa tinggal diam; 2) Mendekati dengan kasih – saya akan mengajak bicara berdua, di tempat yang aman, dengan nada yang lembut. Saya akan bertanya: "Kamu baik-baik saja? Aku melihat kamu beberapa kali... Aku khawatir denganmu. Ada yang bisa aku bantu?"; 3) Mendengarkan tanpa menghakimi – saya akan mendengar alasannya menggunakan narkoba (tekanan, masalah keluarga, atau hanya coba-coba); 4) Melibatkan orang dewasa – saya akan melaporkan kepada pembina remaja atau guru BK yang terpercaya, karena ini di luar kemampuan saya. Saya tidak akan diam karena takut dianggap "ngadu". Menyelamatkan nyawa lebih penting dari popularitas; 5) Mendampingi proses pemulihan – jika dia mau direhabilitasi, saya akan mendukungnya dengan doa dan kunjungan. Saya akan tetap berteman dan tidak mengucilkannya. Seperti dalam Galatia 6:1, "Kembalikanlah orang yang melakukan pelanggaran dengan roh lemah lembut."', 'Poin penilaian: Keberanian moral untuk bertindak (tidak diam), pendekatan yang penuh kasih dan tidak menghakimi, pelibatan otoritas yang kompeten, dukungan berkelanjutan, landasan Alkitab. Juri menilai tanggung jawab sosial dan keberanian.', 'final'),
(29, 'Bagaimana cara Anda mengelola stres dan kecemasan menghadapi ujian atau tekanan akademik?', 'Saya mengelola stres dengan strategi spiritual, mental, dan praktis. Spiritual: 1) Doa dan penyerahan – Filipi 4:6-7, saya menyerahkan kekhawatiran saya kepada Tuhan, percaya bahwa Dia memberi hikmat; 2) Membaca janji Tuhan – seperti Yeremia 29:11, "Aku tahu rancangan-Ku untukmu, rancangan damai sejahtera." Mental: 3) Berpikir positif – saya mengubah pikiran "Saya pasti gagal" menjadi "Saya sudah belajar, Tuhan menyertai"; 4) Tidak membandingkan – saya tidak membandingkan nilai saya dengan teman, setiap orang punya kemampuan berbeda. Praktis: 5) Belajar teratur – saya tidak belajar sistem SKS (Sistem Kebut Semalam), tetapi belajar sedikit demi sedikit setiap hari; 6) Istirahat cukup – tidur minimal 7 jam, karena otak yang lelah tidak bisa berpikir optimal; 7) Olahraga ringan – jalan-jalan atau stretching untuk melepaskan ketegangan; 8) Makan sehat – tidak skip sarapan, kurangi junk food. Saya juga memiliki support system – saya curhat ke orang tua atau sahabat saat stres. Hasilnya: nilai saya tetap baik, dan saya tidak mudah cemas.', 'Poin penilaian: Strategi holistik (spiritual, mental, praktis), penggunaan ayat Alkitab, kebiasaan belajar yang sehat, manajemen stres yang terbukti efektif, kesadaran akan pentingnya istirahat dan dukungan sosial. Juri menilai kematangan dalam mengelola tekanan akademik.', 'final'),
(30, 'Apa sumbangsih pemuda/gereja dalam memajukan pariwisata dan ekonomi kreatif di Sulawesi Utara?', 'Sumbangsih nyata yang bisa saya lakukan sebagai remaja: 1) Menjadi duta wisata dadakan – ketika ada turis asing yang tersesat, saya bisa membantu dengan Bahasa Inggris saya dan merekomendasikan tempat wisata seperti Bunaken, Danau Tondano, atau Bukit Kasih; 2) Membuat konten promosi – saya bisa membuat video TikTok atau YouTube tentang keindahan Sulut dengan bahasa Indonesia dan Inggris, menggunakan tagar #PesonaSulut #WonderfulIndonesia; 3) Mengembangkan produk kreatif berbasis budaya – saya bisa membuat gantungan kunci dari kayu kolintang mini, atau menjual Tinutuan bubuk instan yang dikemas menarik untuk oleh-oleh; 4) Melibatkan gereja – gereja bisa mengadakan bazar kuliner tradisional setelah ibadah, atau menggelar festival budaya kolintang yang bisa dinikmati wisatawan; 5) Menjadi relawan event pariwisata – seperti Festival Likupang atau Sail Tomoni, saya bisa membantu sebagai pemandu atau panitia. Saya percaya bahwa pariwisata dan ekonomi kreatif yang maju akan meningkatkan kesejahteraan masyarakat Sulut, dan gereja bisa menjadi bagian dari solusi.', 'Poin penilaian: Pemahaman tentang potensi pariwisata Sulut, aksi konkret yang bisa dilakukan remaja, kreativitas dalam ekonomi kreatif, keterlibatan gereja, semangat membangun daerah. Juri menilai nasionalisme lokal dan kewirausahaan.', 'final'),
(31, 'Bagaimana Anda akan merespon jika orang tua Anda melarang Anda ikut kegiatan gereja karena alasan akademik?', 'Saya akan merespon dengan hormat dan komunikasi yang baik, bukan dengan marah atau ngambek. Langkah saya: 1) Mendengarkan dulu – saya akan bertanya dengan sopan: "Bapak/Ibu, apa alasan spesifiknya? Apakah nilai saya turun? Atau khawatir waktu belajar kurang?" 2) Menghargai kekhawatiran orang tua – saya akan mengakui bahwa mereka peduli pada masa depan saya; 3) Menawarkan solusi win-win – "Bagaimana kalau saya tetap ikut kegiatan gereja, tetapi saya buktikan bahwa nilai saya tidak turun? Saya akan belajar lebih giat. Atau, bolehkah saya memilih hanya 2 kegiatan saja yang paling penting?" 4) Menunjukkan bukti – saya akan menunjukkan rapor bahwa nilai saya baik, atau mengajak orang tua berbicara dengan pembina remaja; 5) Mentaati keputusan orang tua – jika setelah diskusi mereka tetap melarang, untuk sementara saya akan taat, sambil terus berdoa dan berusaha meyakinkan mereka dengan prestasi akademik yang meningkat. Efesus 6:1 berkata, "Hormatilah ayahmu dan ibumu." Saya percaya bahwa seiring waktu, orang tua akan melihat bahwa kegiatan gereja tidak merusak akademik saya.', 'Poin penilaian: Sikap hormat kepada orang tua (tidak melawan), komunikasi yang dewasa, solusi konkret (menawarkan kompromi), kesediaan taat sambil terus berusaha, landasan Alkitab. Juri menilai kematangan dalam hubungan dengan orang tua.', 'final'),
(32, 'Apa yang akan Anda lakukan jika diminta menjadi ketua panitia acara besar, tetapi Anda merasa tidak mampu?', 'Saya akan merespon dengan jujur tetapi tidak menyerah. Langkah saya: 1) Mengakui keterbatasan – saya akan berkata, "Terima kasih atas kepercayaannya. Jujur, saya merasa belum cukup pengalaman untuk acara sebesar ini. Tapi saya tidak akan menolak mentah-mentah." 2) Meminta pendampingan – "Apakah boleh saya didampingi oleh senior atau pembina yang lebih berpengalaman?" 3) Belajar dengan cepat – saya akan membaca buku tentang manajemen acara, bertanya pada mantan ketua panitia, dan mencari template dokumen yang diperlukan; 4) Membentuk tim yang kuat – saya tidak akan bekerja sendiri. Saya akan merekrut wakil ketua yang berpengalaman, dan membagi tugas dengan jelas; 5) Berdoa dan percaya – saya ingat perkataan Tuhan kepada Yosua: "Kuatkan dan teguhkanlah hatimu" (Yosua 1:9). Tuhan tidak memanggil yang mampu, tetapi memampukan yang dipanggil. Saya akan menerima tantangan ini sebagai kesempatan untuk bertumbuh, dan memberikan yang terbaik.', 'Poin penilaian: Kejujuran tentang keterbatasan, kerendahan hati untuk minta bantuan, strategi untuk mengatasi ketidakmampuan (belajar cepat, tim yang kuat), iman kepada Tuhan, keberanian untuk menerima tantangan. Juri menilai kematangan dalam menghadapi tanggung jawab besar.', 'final'),
(33, 'Menurut Anda, apa dampak positif dan negatif dari penggunaan AI (Artificial Intelligence) seperti ChatGPT bagi remaja?', 'Dampak positif: 1) Membantu belajar – AI bisa menjelaskan konsep sulit dengan cara yang mudah dipahami; 2) Meningkatkan kreativitas – AI bisa membantu membuat kerangka tulisan, ide konten, atau bahkan lirik lagu; 3) Efisiensi waktu – mencari informasi lebih cepat; 4) Belajar bahasa – AI bisa menjadi tutor Bahasa Inggris yang sabar. Dampak negatif: 1) Mengurangi kemampuan berpikir kritis – remaja jadi malas berpikir karena tinggal copy-paste; 2) Kecurangan akademik – menggunakan AI untuk mengerjakan tugas tanpa memahami materinya; 3) Informasi yang salah – AI bisa memberikan jawaban yang salah atau bias; 4) Ketergantungan – remaja kehilangan kemampuan menulis dan menganalisis sendiri. Sikap saya: AI adalah alat, bukan tuhan. Saya akan menggunakan AI sebagai asisten, bukan pengganti otak saya. Saya akan tetap mengerjakan tugas sendiri, menggunakan AI hanya untuk riset awal atau proofreading. Saya juga akan selalu cross-check informasi dari AI dengan sumber terpercaya. Yang terpenting, saya tidak akan kehilangan kreativitas dan originalitas saya sebagai ciptaan Tuhan yang unik.', 'Poin penilaian: Pemahaman tentang teknologi terkini, analisis seimbang (positif dan negatif), sikap kritis terhadap teknologi, tidak anti-teknologi tetapi tidak juga bergantung berlebihan, penekanan pada originalitas sebagai ciptaan Tuhan. Juri menilai literasi digital dan kemampuan berpikir kritis.', 'final'),
(34, 'Bagaimana cara Anda mempertahankan iman ketika berada di lingkungan sekolah yang mayoritas non-Kristen dan kadang mengejek keyakinan Anda?', 'Saya mempertahankan iman dengan 3 prinsip: 1) Tetap rendah hati tetapi tidak malu – saya tidak akan menyembunyikan iman saya, tetapi juga tidak memprovokasi. Jika diejek, saya akan menjawab dengan senyum: "Itu keyakinanku, aku menghormati keyakinanmu, tolong hormati juga keyakinanku." Saya ingat 1 Petrus 3:15, "Jawablah dengan lemah lembut dan hormat." 2) Membuktikan dengan perbuatan – saya tidak hanya bicara, tetapi menunjukkan bahwa iman saya membuat saya menjadi pribadi yang lebih baik: jujur, suka menolong, tidak membully, dan berprestasi. Ketika teman-teman melihat perbedaan positif, mereka tidak akan mengejek; 3) Mencari komunitas – saya memiliki teman-teman Kristen di sekolah untuk saling menguatkan. Kami berdoa bersama di jam istirahat, saling mengingatkan. Jika ejekan sudah keterlaluan, saya akan melaporkan ke guru BK. Saya tidak akan membalas ejekan dengan kemarahan, karena Yesus sendiri ketika diolok-olok di kayu salib, Ia berdoa, "Ya Bapa, ampunilah mereka."', 'Poin penilaian: Keteguhan iman tanpa menjadi provokatif, sikap lemah lembut dalam menghadapi ejekan, membuktikan iman melalui perbuatan, mencari dukungan komunitas, teladan Yesus. Juri menilai ketahanan iman dalam konteks minoritas.', 'final'),
(35, 'Apa kritik Anda terhadap pelayanan remaja di gereja saat ini, dan saran perbaikannya?', 'Dengan rendah hati, saya ingin menyampaikan kritik membangun. Kritik: 1) Terlalu formal dan membosankan – banyak ibadah remaja yang monoton, khotbah terlalu panjang, lagu-lagu lama yang tidak familiar; 2) Kurang melibatkan remaja – remaja hanya menjadi penonton, tidak diberi kesempatan untuk berkontribusi; 3) Kurang relevan dengan pergumulan remaja – materi jarang membahas topik seperti pacaran sehat, tekanan teman sebaya, kesehatan mental, atau media sosial; 4) Kurang perhatian pada remaja yang bermasalah – yang aktif-aktif saja yang diperhatikan. Saran perbaikan: 1) Ibadah yang kreatif – gunakan multimedia, musik yang up-to-date, khotbah singkat 20 menit dengan ilustrasi yang relevan; 2) Memberdayakan remaja – bentuk tim kreatif yang terdiri dari remaja untuk merancang ibadah; 3) Pendalaman Alkitab tematik – bahas topik-topik yang relevan dengan kehidupan remaja; 4) Pendampingan personal – setiap remaja memiliki mentor (pembina) yang secara rutin bertemu untuk curhat dan didoakan; 5) Evaluasi rutin – adakan kotak saran anonim agar remaja bisa memberikan masukan tanpa takut. Saya siap membantu mewujudkan saran-saran ini jika diberi kepercayaan.', 'Poin penilaian: Keberanian untuk mengkritik dengan hormat (tidak menghakimi), kritik yang spesifik dan konstruktif, solusi yang realistis, semangat untuk terlibat dalam perbaikan, kerendahan hati. Juri menilai kepemimpinan yang visioner dan kritis.', 'final'),
(36, 'Bagaimana Anda akan meyakinkan teman yang ragu-ragu bahwa Yesus adalah satu-satunya Juruselamat?', 'Saya akan meyakinkan dengan pendekatan yang bertahap dan penuh kasih, bukan dengan paksaan. Langkah saya: 1) Mendengarkan keraguannya – saya akan bertanya, "Apa yang membuatmu ragu? Apakah karena...?" Saya akan mendengarkan tanpa memotong; 2) Menjawab dengan lembut – saya tidak akan berdebat keras. Saya akan menjawab dengan logika dan kesaksian pribadi. Contoh: "Aku dulu juga ragu, tapi setelah aku mempraktekkan ajaran Yesus – mengampuni orang yang menyakitiku, hidupku jadi lebih damai. Aku tidak bisa membuktikan secara ilmiah, tetapi aku merasakan perubahan dalam hidupku." 3) Mengajak membaca Alkitab bersama – "Maukah kamu membaca Injil Markus bersama saya? Kita baca satu pasal setiap minggu, lalu diskusikan." 4) Mengajak ke acara yang tidak mengintimidasi – "Gerejaku ada acara bakti sosial atau konser musik, yuk ikut. Kamu tidak perlu ikut ibadah kalau belum siap." 5) Mendoakan dan bersabar – saya akan berdoa untuk dia setiap hari, dan tidak memaksakan. Saya percaya bahwa Roh Kudus yang bekerja menginsafkan orang akan dosa dan kebenaran (Yohanes 16:8). Tugas saya hanya menabur, Tuhan yang menumbuhkan (1 Korintus 3:6).', 'Poin penilaian: Pendekatan yang tidak memaksa, mendengarkan keraguan dengan empati, menjawab dengan kesaksian pribadi (bukan debat teologis yang rumit), mengajak bertahap, kesabaran dan doa. Juri menilai kearifan dalam penginjilan dan pemahaman tentang karya Roh Kudus.', 'final'),
(37, 'Apa yang akan Anda lakukan jika menjadi Remaja Teladan tetapi kemudian melakukan kesalahan atau dosa yang memalukan?', 'Jika saya jatuh dalam dosa, langkah saya: 1) Bertobat segera kepada Tuhan – saya akan mengaku dosa saya kepada Tuhan dengan tulus, tidak menutup-nutupi. Saya percaya 1 Yohanes 1:9, "Jika kita mengaku dosa kita, Allah adalah setia dan adil, sehingga Ia akan mengampuni segala dosa kita." 2) Mengaku kepada pembina – saya akan mencari pembina remaja yang saya percaya, mengaku dengan jujur, dan meminta bimbingan rohani. Saya tidak akan menyembunyikan karena takut kehilangan gelar; 3) Menerima konsekuensi – jika gelar Remaja Teladan dicabut, saya akan menerimanya dengan rendah hati, karena saya memang gagal menjadi teladan. Saya tidak akan menyalahkan orang lain atau mencari alasan; 4) Minta maaf kepada publik – jika dosa saya diketahui umum, saya akan minta maaf secara terbuka kepada jemaat, tanpa drama, dengan ketulusan; 5) Bangkit kembali – saya tidak akan tinggal dalam keputusasaan. Saya akan belajar dari kesalahan, memperbaiki diri, dan terus melayani Tuhan dari level terendah. Seperti Petrus yang menyangkal Yesus tiga kali tetapi diampuni dan dipulihkan, saya percaya Tuhan masih memberi kesempatan kedua.', 'Poin penilaian: Kejujuran dan pertobatan sejati (bukan menutupi), kerendahan hati untuk minta bantuan, menerima konsekuensi dengan dewasa, minta maaf kepada publik jika perlu, semangat untuk bangkit kembali (resiliensi), teladan Petrus. Juri menilai integritas dalam kegagalan dan pemahaman tentang anugerah.', 'final'),
(38, 'Menurut Anda, apa penyebab utama remaja GMIM kurang bersemangat dalam pelayanan, dan bagaimana solusinya?', 'Penyebab utama: 1) Kurangnya pemahaman akan panggilan – banyak remaja menganggap pelayanan hanya kewajiban, bukan kesempatan; 2) Kegiatan yang monoton – itu-itu saja, tidak ada inovasi; 3) Kurangnya apresiasi – remaja yang sudah melayani jarang diberi penghargaan, malah sering dikritik; 4) Konflik internal – perselisihan antar remaja atau dengan pembina; 5) Prioritas dunia – studi, pacaran, main game lebih menarik. Solusi: 1) Pembinaan panggilan – adakan retret atau seminar tentang "panggilan remaja sebagai imamat yang rajani" (1 Petrus 2:9); 2) Inovasi kegiatan – libatkan remaja dalam merancang kegiatan yang menarik dan relevan; 3) Sistem apresiasi – beri penghargaan sederhana (sertifikat, makan bersama, atau ucapan terima kasih publik) untuk remaja yang setia melayani; 4) Penyelesaian konflik – adakan mediasi jika ada konflik, bangun budaya saling mengasihi; 5) Mentoring – setiap remaja didampingi mentor yang bisa menjadi teladan dan teman curhat. Saya percaya bahwa ketika remaja merasa dihargai, dilibatkan, dan memiliki tujuan yang jelas, semangat pelayanan akan bangkit dengan sendirinya.', 'Poin penilaian: Analisis penyebab yang mendalam (tidak hanya menyalahkan remaja), solusi yang holistik dan sistemik, keterlibatan remaja dalam solusi, apresiasi dan mentoring, landasan Alkitab. Juri menilai pemahaman tentang manajemen pelayanan dan psikologi remaja.', 'final'),
(39, 'Bagaimana Anda meneladani Yesus dalam kehidupan sehari-hari sebagai remaja?', 'Saya meneladani Yesus dalam 3 area utama: 1) Dalam pelayanan – Yesus berkata, "Aku datang bukan untuk dilayani, melainkan untuk melayani" (Markus 10:45). Saya meneladani ini dengan: a) Membantu orang tua tanpa diminta, b) Menjadi ketua kelas yang melayani teman-teman, bukan hanya memerintah, c) Rela mengorbankan waktu luang saya untuk mengajar adik kelas; 2) Dalam doa – Yesus sering berdoa sendirian (Markus 1:35). Saya meneladani ini dengan memiliki waktu teduh setiap pagi sebelum berangkat sekolah, meski hanya 15 menit; 3) Dalam pengampunan – Yesus mengampuni musuh-Nya di kayu salib. Saya meneladani ini dengan memaafkan teman yang menghina saya, tidak menyimpan dendam, bahkan mendoakannya. 4) Dalam kasih – Yesus mengasihi tanpa syarat. Saya meneladani ini dengan menolong siapapun yang membutuhkan, tanpa melihat suku, agama, atau status sosial. Saya sadar bahwa saya belum sempurna seperti Yesus, tetapi setiap hari saya berusaha menjadi lebih serupa dengan Dia.', 'Poin penilaian: Spesifik (bukan jawaban umum "saya baik"), contoh-contoh konkret dari kehidupan remaja, area yang beragam (pelayanan, doa, pengampunan, kasih), kerendahan hati mengakui ketidaksempurnaan, fokus pada keteladanan Yesus. Juri menilai pemahaman tentang inkarnasi dan aplikasinya dalam kehidupan nyata.', 'final'),
(40, 'Apa pesan Anda untuk remaja GMIM yang merasa tidak berguna atau tidak memiliki bakat untuk melayani?', 'Pesan saya: Setiap remaja berguna di mata Tuhan! Anda tidak perlu memiliki bakat yang spektakuler untuk melayani. Di gereja, banyak pelayanan sederhana yang bisa dilakukan: 1) Menjadi notulis dalam rapat; 2) Membersihkan ruang ibadah setelah kegiatan; 3) Menyapa dan menyambut tamu yang datang; 4) Mendoakan teman yang sedang sakit; 5) Membagikan snack setelah ibadah; 6) Mengoperasikan slide presentasi sederhana. Dalam 1 Korintius 12:22, Paulus berkata bahwa anggota tubuh yang kelihatannya paling lemah justru sangat diperlukan. Tuhan tidak melihat seberapa besar bakat Anda, tetapi seberapa besar hati Anda untuk melayani. Contoh: dalam tim pembersih, mungkin tidak ada yang melihat, tetapi tanpa mereka gereja akan kotor. Saya mengajak: Mulailah dari hal kecil, lakukan dengan sukacita, dan Tuhan akan memercayakan hal yang lebih besar. Jangan pernah berkata, "Aku tidak berguna." Dalam Kristus, setiap orang punya peran penting.', 'Poin penilaian: Pesan yang menguatkan dan inklusif (tidak hanya untuk yang berbakat), contoh pelayanan sederhana yang bisa dilakukan siapa saja, landasan Alkitab (1 Korintus 12), dorongan untuk memulai dari hal kecil, semangat bahwa setiap orang berharga. Juri menilai empati dan kemampuan memberdayakan orang lain.', 'final'),
(41, 'Bagaimana Anda akan mengatasi konflik antara remaja dan pembina yang disebabkan oleh perbedaan gaya komunikasi?', 'Saya akan bertindak sebagai jembatan komunikasi antara kedua belah pihak. Langkah saya: 1) Mendengarkan kedua sisi – saya akan berbicara dengan remaja secara pribadi: "Kamu kenapa? Apa yang membuatmu kesal dengan pembina?" Saya juga akan berbicara dengan pembina: "Pak/Bu, maaf, boleh saya tahu perspektif Bapak/Ibu?" 2) Mencari akar masalah – biasanya konflik terjadi karena miskomunikasi. Contoh: pembina yang tegas dianggap galak, padahal hanya ingin disiplin. Atau remaja yang santai dianggap tidak serius, padahal punya cara kerja sendiri; 3) Memfasilitasi pertemuan mediasi – saya akan mengatur pertemuan antara remaja dan pembina di tempat netral, dengan suasana yang santai (misalnya sambil makan bersama). Saya akan memandu diskusi dengan aturan: setiap orang diberi kesempatan bicara tanpa dipotong, fokus pada perasaan bukan menyalahkan; 4) Mencari solusi bersama – misalnya, "Bagaimana kalau ke depan, pembina menyampaikan kritik secara pribadi dulu, bukan di depan umum?" atau "Remaja berjanji akan lebih tepat waktu." 5) Tindak lanjut – saya akan memantau apakah kesepakatan dijalankan. Saya ingat Amsal 15:1, "Jawaban yang lemah lembut meredakan kegeraman." Konflik bukan akhir dari segalanya, tetapi bisa menjadi awal dari pemahaman yang lebih baik.', 'Poin penilaian: Peran sebagai mediator (bukan memihak), kemampuan mendengarkan kedua sisi, fasilitasi pertemuan yang konstruktif, mencari solusi bersama, tindak lanjut, landasan Alkitab. Juri menilai keterampilan resolusi konflik dan kecerdasan interpersonal.', 'final'),
(42, 'Apa yang Anda ketahui tentang "Gereja Global" dan bagaimana remaja GMIM dapat berperan di dalamnya?', 'Gereja Global adalah visi GMIM untuk menjadi gereja yang tidak terbatas oleh geografis, melayani tidak hanya di Minahasa atau Indonesia, tetapi di seluruh dunia. Ini sejalan dengan Amanat Agung Yesus: "Pergilah ke seluruh dunia, beritakan Injil kepada segala makhluk" (Markus 16:15). Peran remaja GMIM dalam Gereja Global: 1) Menjadi missioner muda – melalui program pertukaran pemuda antar gereja, atau magang di gereja mitra di luar negeri; 2) Memanfaatkan teknologi – membuat konten rohani dalam Bahasa Inggris yang bisa diakses oleh remaja di seluruh dunia; 3) Belajar bahasa asing – minimal Bahasa Inggris, agar bisa berkomunikasi dengan remaja dari negara lain; 4) Mendukung misi pengutusan – melalui doa dan dana, remaja bisa mendukung pendeta/guru agama yang diutus ke luar negeri; 5) Menjadi duta budaya dan iman – ketika berkesempatan studi atau traveling ke luar negeri, remaja bisa memperkenalkan GMIM dan budaya Minahasa sekaligus bersaksi. Saya bermimpi suatu hari nanti bisa menjadi utusan remaja GMIM ke gereja mitra di Belanda atau Amerika, belajar dari mereka, dan membawa pulang inspirasi untuk memajukan pelayanan remaja di tanah air.', 'Poin penilaian: Pemahaman tentang visi Gereja Global, contoh konkret peran remaja, penggunaan teknologi, semangat misi dan pengutusan, mimpi yang visioner. Juri menilai wawasan global dan semangat misi.', 'final'),
(43, 'Bagaimana Anda akan menyikapi teman yang mengalami kecanduan game online hingga mengabaikan ibadah dan belajar?', 'Saya akan menyikapi dengan kasih, bukan kemarahan atau ejekan. Langkah saya: 1) Mendekati dengan empati – "Aku lihat kamu sering main game sampai larut. Kamu baik-baik saja? Ada masalah yang membuatmu melarikan diri ke game?" Mungkin dia stres dengan pelajaran atau masalah keluarga; 2) Tidak menghakimi – saya tidak akan berkata, "Kamu berdosa, kamu malas," karena itu hanya akan membuatnya defensif; 3) Menawarkan alternatif – "Bagaimana kalau kita olahraga bersama atau belajar bareng? Atau, kamu mau ikut kegiatan seru di gereja minggu ini?" 4) Membuat kesepakatan – "Bagaimana kalau kita saling mengingatkan? Aku akan ingatkan kamu kalau sudah waktunya ibadah, kamu ingatkan aku kalau aku lalai." 5) Melibatkan orang tua/pembina – jika kecanduannya sudah parah (bermain >6 jam sehari, mengabaikan sekolah), saya akan berbicara dengan orang tua atau pembina remaja untuk mencari solusi bersama, seperti membuat jadwal bermain game yang terbatas; 6) Mendoakan – saya akan berdoa untuk dia setiap hari, memohon Tuhan memulihkannya. Saya percaya bahwa di balik kecanduan, selalu ada luka atau kebutuhan yang tidak terpenuhi. Tugas saya adalah menjadi sahabat yang mendampingi, bukan hakim yang menghakimi.', 'Poin penilaian: Empati (mencari akar masalah), tidak menghakimi, menawarkan alternatif positif, membuat kesepakatan, pelibatan orang dewasa jika perlu, doa, pemahaman bahwa kecanduan adalah masalah kompleks. Juri menilai kepedulian sosial dan pendekatan yang bijaksana terhadap adiksi digital.', 'final'),
(44, 'Menurut Anda, apa kelebihan sistem Presbiterial Sinodal dibandingkan sistem gereja lainnya?', 'Kelebihan sistem Presbiterial Sinodal yang saya alami di GMIM: 1) Kepemimpinan kolektif, bukan individual – keputusan tidak diambil oleh satu orang (seperti uskup dalam sistem episkopal), tetapi oleh tim (para presbiter). Ini mengurangi risiko otoritarianisme dan kesalahan individu; 2) Musyawarah mufakat – keputusan diambil melalui diskusi bersama, bukan voting yang bisa memecah belah. Ini sesuai dengan budaya Indonesia dan ajaran Alkitab tentang kesatuan tubuh Kristus; 3) Keterwakilan – setiap jemaat terwakili dalam sidang di tingkat wilayah dan sinode, sehingga suara dari bawah didengar; 4) Keseimbangan antara otonomi dan persatuan – jemaat memiliki otonomi dalam hal-hal tertentu, tetapi tetap dalam satu kesatuan GMIM; 5) Akuntabilitas – setiap pemimpin (BPMJ, BPMW, BPMS) bertanggung jawab kepada sidang majelis, bukan hanya kepada atasannya. Contoh konkret: dalam pemilihan Remaja Teladan, panitia dan juri tidak bisa bertindak seenaknya karena ada pengawasan dari KPRS dan aturan yang jelas. Saya bersyukur GMIM memiliki sistem yang demokratis, alkitabiah, dan sesuai dengan budaya kita.', 'Poin penilaian: Pemahaman tentang sistem pemerintahan gereja, analisis kelebihan yang spesifik, perbandingan implisit dengan sistem lain (tanpa merendahkan), contoh konkret, apresiasi terhadap sistem GMIM. Juri menilai pengetahuan tentang Tata Gereja dan kebanggaan terhadap sistem GMIM.', 'final'),
(45, 'Bagaimana Anda akan memotivasi remaja yang malas membaca Alkitab?', 'Saya akan memotivasi dengan pendekatan yang menyenangkan dan bertahap. Langkah saya: 1) Menanyakan alasannya – "Kamu kenapa malas baca Alkitab? Apakah karena bahasanya sulit? Atau merasa bosan? Atau tidak tahu harus mulai dari mana?" 2) Memberi rekomendasi yang sesuai – jika bahasanya sulit, saya sarankan Alkitab terjemahan BIMK atau Firman Allah Yang Hidup yang lebih mudah dipahami; jika bosan, saya ajak menggunakan aplikasi Alkitab yang interaktif seperti YouVersion yang memiliki rencana baca dengan pengingat dan fitur sosial; 3) Membuat tantangan bersama – "Ayo kita ikut tantangan baca 1 pasal sehari selama 30 hari. Yang konsisten, kita traktir makan bakti!" 4) Menjadi teladan – saya akan mengajak dia membaca bersama: "Bagaimana kalau kita WA-an setiap malam, kita baca pasal yang sama, lalu kita sharing?" 5) Menjelaskan manfaat – "Baca Alkitab itu bukan kewajiban agama, tetapi seperti menerima surat cinta dari Tuhan. Semakin sering kita baca, semakin kita mengenal Tuhan dan hidup kita akan diubahkan." 6) Doa bersama – "Mari kita berdoa, minta Roh Kudus menumbuhkan kerinduan untuk membaca Firman." Saya percaya bahwa ketika seseorang mengalami sendiri bagaimana Firman Tuhan berbicara dalam hidupnya, dia tidak akan mau berhenti membacanya.', 'Poin penilaian: Pendekatan yang personal (bukan generalisasi), solusi kreatif (aplikasi, tantangan, membaca bersama), menjadi teladan, menjelaskan manfaat rohani, doa, kesabaran. Juri menilai kreativitas dalam pembinaan rohani dan kemampuan memotivasi.', 'final'),
(46, 'Apa kontribusi Anda terhadap lingkungan hidup sebagai remaja teladan?', 'Kontribusi saya terhadap lingkungan hidup: 1) Mengurangi sampah plastik – saya membawa botol minum dan tas belanja sendiri, tidak menggunakan sedotan plastik. Saya juga mengajak teman-teman melakukan hal yang sama; 2) Menanam pohon – setiap bulan, saya menanam minimal 1 pohon di pekarangan rumah atau di lahan kosong sekitar gereja. Saya sudah menanam 12 pohon dalam setahun terakhir; 3) Menghemat energi – saya mematikan lampu dan AC jika tidak digunakan, mencabut charger dari stopkontak, dan menggunakan transportasi umum atau bersepeda jika memungkinkan; 4) Mengadakan aksi bersih-bersih – saya pernah menginisiasi "Jumat Bersih" di sekolah, di mana setiap Jumat kami memungut sampah di lingkungan sekolah selama 15 menit sebelum belajar; 5) Mengedukasi – saya membuat konten Instagram tentang tips hidup ramah lingkungan, seperti cara mengolah sampah organik menjadi pupuk kompos. Alasan saya peduli lingkungan: karena ini adalah ciptaan Tuhan yang dipercayakan kepada kita untuk dijaga (Kejadian 2:15). Sebagai remaja teladan, saya harus menjadi penjaga bumi yang bertanggung jawab, bukan perusak.', 'Poin penilaian: Aksi konkret yang sudah dilakukan (bukan rencana), dampak yang terukur (12 pohon), inisiatif pribadi dan ajakan kepada orang lain, edukasi melalui media sosial, landasan Alkitab (stewardship). Juri menilai kepedulian lingkungan dan konsistensi tindakan.', 'final'),
(47, 'Bagaimana Anda akan memimpin doa di depan umum (misalnya di upacara bendera) yang dihadiri oleh orang-orang yang berbeda agama?', 'Saya akan memimpin doa dengan inklusif namun tetap setia pada iman Kristen. Prinsip saya: 1) Menggunakan bahasa yang umum – "Kami bersyukur kepada Tuhan Yang Maha Kuasa" (yang diakui oleh semua agama), bukan "Kami bersyukur kepada Yesus Kristus" (khusus Kristen); 2) Isi doa yang netral – memohon kesehatan, keselamatan, kelancaran acara, dan kebijaksanaan bagi pemimpin, yang bisa diamin oleh semua orang; 3) Tidak menyinggung keyakinan orang lain – tidak menggunakan ayat Alkitab secara eksplisit, tidak menyebut "dalam nama Yesus" di akhir doa; 4) Menjaga sikap hormat – saya akan berdoa dengan sikap yang sopan (tangan tertutup, kepala sedikit menunduk), tidak berlebihan; 5) Menjelaskan jika diminta – jika ada yang bertanya, "Kamu Kristen, kenapa doamu tidak pakai nama Yesus?" saya akan menjelaskan: "Saya berdoa dalam hati menggunakan nama Yesus, tetapi diucapkan dengan bahasa umum agar semua bisa mengamininya. Ini bentuk penghormatan saya pada teman-teman yang berbeda iman." Saya ingat 1 Korintus 9:22, "Aku telah menjadi segala sesuatu bagi semua orang, supaya aku dapat menyelamatkan beberapa orang." Saya tidak mengkompromikan iman, tetapi menyesuaikan cara penyampaian demi menjaga kerukunan.', 'Poin penilaian: Keseimbangan antara kesetiaan iman dan penghormatan pada perbedaan, strategi yang bijaksana (bahasa umum, isi netral), sikap hormat, kesiapan menjelaskan jika ditanya, landasan Alkitab tentang menjadi "segala sesuatu bagi semua orang". Juri menilai kearifan dalam konteks pluralisme.', 'final'),
(48, 'Apa yang akan Anda lakukan untuk mencegah perundungan (bullying) di lingkungan sekolah dan gereja?', 'Saya akan melakukan 3 strategi: preventif, intervensi, dan kuratif. Preventif (pencegahan): 1) Edukasi – mengadakan sosialisasi tentang dampak bullying melalui poster, drama, atau seminar di sekolah dan gereja; 2) Membangun budaya positif – menginisiasi program "Sahabat Bicara" di mana setiap siswa memiliki teman yang bisa diajak curhat; 3) Menjadi teladan – saya tidak akan pernah ikut-ikutan mengejek atau mengucilkan siapapun. Intervensi (saat terjadi): 4) Berani menegur – jika melihat bullying, saya akan dengan tegas berkata, "Hei, jangan seperti itu. Itu tidak baik." Saya tidak akan diam jadi penonton; 5) Membela korban – saya akan mendekati korban, membawanya pergi dari situasi tersebut, dan meyakinkan bahwa dia tidak sendirian; 6) Melaporkan – jika bullying berulang atau parah, saya akan melapor ke guru atau pembina. Kuratif (pemulihan): 7) Mendampingi korban – saya akan menjadi teman bagi korban, membantu dia membangun kembali rasa percaya dirinya; 8) Membina pelaku – saya akan mendekati pelaku dengan kasih, membantu dia memahami kesalahannya, dan mengajak bertobat. Saya percaya bahwa pencegahan lebih baik dari pengobatan, tetapi jika sudah terjadi, tidak boleh ada yang diam.', 'Poin penilaian: Strategi yang komprehensif (preventif, intervensi, kuratif), keberanian moral untuk bertindak, pendekatan yang berimbang (membela korban, membina pelaku), pelibatan otoritas jika perlu, kepedulian pada pemulihan. Juri menilai keberanian, empati, dan kepemimpinan dalam mengatasi isu sosial.', 'final'),
(49, 'Bagaimana Anda akan merayakan keberhasilan tim tanpa membuat anggota lain yang kurang berkontribusi merasa tersisih?', 'Saya akan merayakan keberhasilan dengan inklusif, bukan eksklusif. Caranya: 1) Mengakui kontribusi semua orang – dalam sambutan atau doa syukur, saya akan menyebutkan semua pihak yang terlibat, termasuk yang tugasnya kecil seperti menyiapkan konsumsi. "Keberhasilan ini berkat kerja keras kita semua, mulai dari ketua panitia sampai yang membersihkan ruangan." 2) Merayakan sebagai tim, bukan individu – saya tidak akan menyebut nama-nama tertentu secara berlebihan. Saya akan mengadakan pesta tim (makan bersama, nonton bareng) yang dihadiri semua orang, tanpa membanding-bandingkan kontribusi; 3) Memberi apresiasi khusus secara pribadi – jika ada anggota yang kurang berkontribusi, saya akan mendekatinya secara pribadi: "Aku tahu kamu mungkin merasa kurang puas dengan kontribusimu. Tapi kehadiranmu saja sudah berarti bagi tim. Lain kali, kita bisa bagi tugas yang lebih sesuai dengan kemampuanmu." 4) Fokus pada pembelajaran, bukan pencapaian – "Kita berhasil, tetapi yang lebih penting adalah kita belajar bekerja sama. Setiap orang punya peran." 5) Menghindari pujian yang membandingkan – tidak mengatakan, "Kamu hebat, beda dengan si X yang tidak melakukan apa-apa." Saya ingat 1 Korintus 12, bahwa tubuh membutuhkan semua anggota, bahkan yang kelihatan paling lemah.', 'Poin penilaian: Kesadaran akan pentingnya inklusivitas, strategi merayakan yang melibatkan semua orang, apresiasi yang adil (tidak membandingkan), fokus pada pembelajaran tim, landasan Alkitab tentang tubuh Kristus. Juri menilai kepemimpinan yang inklusif dan kemampuan membangun tim.', 'final'),
(50, 'Apa mimpi terbesar Anda sebagai remaja GMIM untuk masa depan gereja dan bangsa?', 'Mimpi terbesar saya adalah melihat kebangunan rohani di kalangan remaja GMIM yang berdampak pada transformasi bangsa Indonesia. Saya bermimpi: 1) Remaja GMIM menjadi agen perubahan – bukan hanya mendengar firman, tetapi melakukan firman. Remaja yang berani menjadi terang di sekolah, di masyarakat, dan di dunia digital. Remaja yang menjadi teladan dalam kejujuran, integritas, kasih, dan kepedulian; 2) Gereja GMIM menjadi rumah yang relevan bagi remaja – di mana remaja merasa diterima, didengar, dan diberdayakan. Gereja yang tidak ketinggalan zaman, tetapi tidak juga kehilangan esensi iman; 3) Indonesia yang lebih baik – melalui peran remaja Kristen, saya bermimpi Indonesia menjadi bangsa yang bermartabat, berkeadilan, dan bermoral. Tidak ada lagi korupsi, perundungan, hoaks, dan kebencian. Remaja Kristen menjadi garam dan terang yang mengasinkan dan menerangi bangsa ini; 4) Diri saya sendiri – saya bermimpi menjadi pribadi yang setia kepada Tuhan sampai akhir hayat, tidak peduli apa pun tantangannya. Saya ingin menjadi remaja, pemuda, dan kelak orang dewasa yang berguna bagi Tuhan, gereja, dan bangsa. Mimpi ini mungkin besar, tetapi dengan Tuhan, semua mungkin. Seperti kata Yeremia 29:11, "Aku tahu rancangan-rancangan-Ku untukmu, rancangan damai sejahtera, bukan rancangan kecelakaan, untuk memberikan masa depan yang penuh harapan." Saya percaya mimpi ini akan terwujud jika kita bergerak bersama.', 'Poin penilaian: Visi yang besar tetapi realistis, fokus pada kebangunan rohani dan transformasi sosial, peran remaja sebagai agen perubahan, cita-cita pribadi yang mulia, landasan Alkitab, semangat optimisme dan iman. Juri menilai visi kepemimpinan, semangat melayani, dan komitmen jangka panjang.', 'final');
